```class Solution {
    public int longestSemiRepetitiveSubstring(String s) {
        int maxLen = 0, curLen = 0, prev = -1;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == s.charAt(i - 1) && i > 0) {
                curLen = i - prev;
                maxLen = Math.max(maxLen, curLen);
                prev = i;
                curLen = 1;
            } else {
                curLen++;
            }
        }
        return Math.max(maxLen, curLen);
    }
}```
